import{Cn as e}from"./chunk-Bzf2rILe.js";var t=e(),n={title:`Focused cybersecurity for a small project`,publishing_date:`2026-06-27`,category:`webdev`,secondaryCategory:`blockchain`,description:`Using a lightweight threat model to focus security work on a small project — figuring out what's actually worth protecting, and which alerts to safely ignore.`};function r(e){let n={a:`a`,code:`code`,em:`em`,h2:`h2`,li:`li`,ol:`ol`,p:`p`,strong:`strong`,table:`table`,tbody:`tbody`,td:`td`,th:`th`,thead:`thead`,tr:`tr`,ul:`ul`,...e.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsx)(n.p,{children:`As I work on my website, I keep thinking about cybersecurity. And because I am by no means an expert, I mostly enabled whatever security feature I could find: notably dependabot or CodeQL. However, all of this felt really quite random. Actually, it feels like I keep buying fancy security stuff for my house but I am not quite sure what I am protecting against.`}),`
`,(0,t.jsxs)(n.p,{children:[`So I turned back to the basics of IT security. After some research, I really came to appreciate the approach that is
based on concrete `,(0,t.jsx)(n.a,{href:`https://www.threatmodelingmanifesto.org`,children:`threats`}),`:`]}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`What are the valuable assets of this website that someone would like to steal ?`}),`
`,(0,t.jsx)(n.li,{children:`Who are then realistic actors attacking me and what are they likely looking for ?`}),`
`,(0,t.jsx)(n.li,{children:`How would the attackers likely try to go for the assets ?`}),`
`,(0,t.jsx)(n.li,{children:`And finally: did I actually do a good enough job — or am I just buying more locks ?`}),`
`]}),`
`,(0,t.jsx)(n.p,{children:`What I like about this approach is that it is very closely aligned to my standard security logic:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`I make a little inventory of my valuable assets. This is cash, electronics, the car etc.`}),`
`,(0,t.jsx)(n.li,{children:`Then I think about realistic attackers. These are unlikely to be some state-sponsored armies or big criminal groups. I am just not valuable enough.`}),`
`,(0,t.jsx)(n.li,{children:`Then I go through the likely attacks. This is likely an open window, weakly protected door etc.`}),`
`,(0,t.jsx)(n.li,{children:`And finally: Is my housing secure enough ? Did I put the cash into a bank account that protects the money professionally ?`}),`
`]}),`
`,(0,t.jsx)(n.p,{children:`The neat thing about the threat model is that it directly translates this approach into the digital world. In this post I walk you through it for my website as an example.`}),`
`,(0,t.jsx)(n.h2,{children:`Getting started with the asset list`}),`
`,(0,t.jsxs)(n.p,{children:[`The first question is super straightforward to ask: what actually has value here? The answer is less straightforward as most of the code is open source. So what is left over ? For this project, I have a set of `,(0,t.jsx)(n.a,{href:`/blog/11/`,children:`upgradeable contracts on Optimism`}),`, a `,(0,t.jsx)(n.a,{href:`/blog/9/`,children:`serverless image-gen backend`}),`, an `,(0,t.jsx)(n.a,{href:`/blog/16/`,children:`LLM assistant`}),`, and an `,(0,t.jsx)(n.a,{href:`/blog/22/`,children:`x402 payment facilitator`}),`. The list then looks like this:`]}),`
`,(0,t.jsxs)(n.table,{children:[(0,t.jsx)(n.thead,{children:(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.th,{children:`Asset category`}),(0,t.jsx)(n.th,{children:`What it is here`}),(0,t.jsx)(n.th,{children:`Why it matters`})]})}),(0,t.jsxs)(n.tbody,{children:[(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`The keys to everything`}),(0,t.jsx)(n.td,{children:`Contract owner EOA — owns every upgradeable contract`}),(0,t.jsx)(n.td,{children:`Total system compromise: upgrade any contract, drain every balance`})]}),(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`Money in the system`}),(0,t.jsx)(n.td,{children:`Mint fees in GenImNFTv4, user prepaid balances in LLMv1, USDC settlements in flight`}),(0,t.jsx)(n.td,{children:`Direct financial loss — mine or my users'`})]}),(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`Operational keys`}),(0,t.jsx)(n.td,{children:`Backend agent wallet, facilitator fee wallet`}),(0,t.jsx)(n.td,{children:`Bounded: small per-call value, no upgrade power`})]}),(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`Infrastructure access`}),(0,t.jsx)(n.td,{children:`Serverless secrets — Scaleway, BFL, IONOS`}),(0,t.jsx)(n.td,{children:`Off-chain only: S3, email, image-gen quota; no on-chain reach`})]})]})]}),`
`,(0,t.jsx)(n.p,{children:`Two things fall out immediately from writing this down.`}),`
`,(0,t.jsx)(n.p,{children:`First, the blast radius for each category is obvious — the table is already sorted by it. The top category, the keys to everything, is catastrophic: one key controls every UUPS proxy contract, so whoever holds it can upgrade every contract and drain every balance. Every category below it is bounded: an operational key like the agent wallet can drain GenImNFTv4 at mint price per call but nothing more; infrastructure access loses S3 writes or image-gen quota, with no on-chain reach at all.`}),`
`,(0,t.jsx)(n.p,{children:`Second, you notice what's absent. User wallet keys never touch the server. No PII is collected. These are non-assets — they can't be compromised here because they don't exist here. So the whole decentralized architecture simplifies the security work massively for me. No one can steal from me what I do not possess.`}),`
`,(0,t.jsx)(n.h2,{children:`Who would like to steal these assets ?`}),`
`,(0,t.jsxs)(n.p,{children:[`The asset list itself is only the starting point. Now I also need to guess who might be actually coming for those assets. Again, I have to keep in mind that this is a tiny project with little financial value. So the list is really not that long for a project at this scale. The two columns that matter are `,(0,t.jsx)(n.em,{children:`capability`}),` and `,(0,t.jsx)(n.em,{children:`motivation`}),` — the "primary access" column just spells out the technical entry point for each, and you can happily skim it:`]}),`
`,(0,t.jsxs)(n.table,{children:[(0,t.jsx)(n.thead,{children:(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.th,{children:`Actor`}),(0,t.jsx)(n.th,{children:`Capability`}),(0,t.jsx)(n.th,{children:`Motivation`}),(0,t.jsx)(n.th,{children:`Primary access`})]})}),(0,t.jsxs)(n.tbody,{children:[(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`Opportunistic bot`}),(0,t.jsx)(n.td,{children:`Low — runs known exploit scripts`}),(0,t.jsx)(n.td,{children:`Financial: drain any available ETH`}),(0,t.jsx)(n.td,{children:`Public contract ABI; scans for no-auth functions and reentrancy`})]}),(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`Financially motivated attacker`}),(0,t.jsx)(n.td,{children:`Medium — reads deployed ABIs, may run a malicious site`}),(0,t.jsx)(n.td,{children:`Financial: extract ETH, redirect USDC, mint below market`}),(0,t.jsx)(n.td,{children:`Direct contract calls; crafted ERC721 receivers; cross-origin requests to the facilitator`})]}),(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`Insider / compromised authorized account`}),(0,t.jsx)(n.td,{children:`High — already holds partial on-chain trust or a secret`}),(0,t.jsx)(n.td,{children:`Financial gain or sabotage`}),(0,t.jsxs)(n.td,{children:[(0,t.jsx)(n.code,{children:`authorizedProviders`}),` in LLMv1; agent wallet or SCW secret via credential leak`]})]}),(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`Attacker with owner credentials`}),(0,t.jsx)(n.td,{children:`Critical — holds the owner EOA`}),(0,t.jsx)(n.td,{children:`Total control`}),(0,t.jsxs)(n.td,{children:[`Key leaked via `,(0,t.jsx)(n.code,{children:`.env`}),`, phishing, or a compromised dev machine`]})]})]})]}),`
`,(0,t.jsxs)(n.p,{children:[`From the list above `,(0,t.jsx)(n.a,{href:`/blog/21/`,children:`I already met one`}),`: a professional bot network extracted 80 cents from a missing authorization check in GenImNFTv3, then moved on.`]}),`
`,(0,t.jsx)(n.p,{children:`Nation-states, L1/L2 consensus attacks, and Scaleway infrastructure compromise are explicitly out of scope. Not because they're impossible. But is it realistic that such an attacker comes for a project that barely generates any mint fees ? Unlikely...`}),`
`,(0,t.jsx)(n.h2,{children:`How would they actually get in?`}),`
`,(0,t.jsxs)(n.p,{children:[`Knowing `,(0,t.jsx)(n.em,{children:`who`}),` is coming and `,(0,t.jsx)(n.em,{children:`what`}),` they want now guides the next question. How are the actors likely to attack ? Here, again I have no reason to guess but I can start with the awesome OWASP lists. I leaned on two catalogs that already exist, one for each half of the system:`]}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.a,{href:`https://owasp.org/www-project-smart-contract-top-10/`,children:`OWASP Smart Contract Top 10`}),` for the `,(0,t.jsx)(n.code,{children:`eth/`}),` contracts.`]}),`
`,(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.a,{href:`https://owasp.org/API-Security/editions/2023/en/0x11-t10/`,children:`OWASP API Security Top 10`}),` for the serverless functions and the website.`]}),`
`]}),`
`,(0,t.jsxs)(n.p,{children:[`The value here is that I inherit a checklist the whole industry has already vetted, instead of inventing my own list of ways things go wrong. The point isn't to walk all twenty categories, though — it's to list only the ones that are actually `,(0,t.jsx)(n.em,{children:`important`}),` for this system. Here are a few concrete entries, in plain terms:`]}),`
`,(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:`Contract layer.`}),` `,(0,t.jsx)(n.em,{children:`Access control (SC01)`}),` — can someone call a function they're not allowed to? — is the one that already bit me: the missing authorization check on `,(0,t.jsx)(n.code,{children:`requestImageUpdate()`}),` that the bot drained, now closed with an agent whitelist. `,(0,t.jsx)(n.em,{children:`Reentrancy (SC08)`}),` — can someone slip back into a half-finished transaction to squeeze it? — applies to CollectorNFT's mint-price path; it's open, but the impact is price manipulation only, no fund theft, so it sits low on the list rather than at the top.`]}),`
`,(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:`API layer.`}),` `,(0,t.jsx)(n.em,{children:`Broken function-level authorization (API5)`}),` — can a random website call my endpoints? — covers the facilitator's wide-open CORS, accepted on purpose because the payment cryptography (EIP-3009) binds recipient, amount, and nonce, so an open origin can't redirect a cent. `,(0,t.jsx)(n.em,{children:`Unrestricted resource consumption (API4)`}),` — can someone spam me until it costs me? — covers `,(0,t.jsx)(n.code,{children:`/settle`}),` spam draining gas, also accepted, because L2 gas is fractions of a cent and the wallet's ETH goes to miners, not the attacker.`]}),`
`,(0,t.jsx)(n.p,{children:`And this is really where the threat model starts to pay off. Once I mapped through the threats, I can really decide on the value of my fixes:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`Grading my own fixes becomes "which category did this touch, and did it matter?"`}),`
`,(0,t.jsx)(n.li,{children:`Triaging an incoming CVE stops being a judgment call and becomes a lookup — which category does this fall under, and what did I already decide about it?`}),`
`]}),`
`,(0,t.jsx)(n.h2,{children:`Application example: Grading my recent security fixes`}),`
`,(0,t.jsx)(n.p,{children:`With the asset list and actor table in place, I ran my recent security changes through them. Here's the honest result:`}),`
`,(0,t.jsxs)(n.table,{children:[(0,t.jsx)(n.thead,{children:(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.th,{children:`What I changed`}),(0,t.jsx)(n.th,{children:`Could anyone actually exploit it?`}),(0,t.jsx)(n.th,{children:`Verdict`})]})}),(0,t.jsxs)(n.tbody,{children:[(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`Moved the master key into its own dedicated wallet`}),(0,t.jsx)(n.td,{children:`Only mattered if the key already leaked`}),(0,t.jsx)(n.td,{children:`Good hygiene, not a bug`})]}),(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`Made login signatures expire after 5 minutes`}),(0,t.jsx)(n.td,{children:(0,t.jsx)(n.strong,{children:`Yes — a copied signature worked forever before`})}),(0,t.jsx)(n.td,{children:`The one real bug`})]}),(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`Made a failed payment batch error out instead of passing silently`}),(0,t.jsx)(n.td,{children:`Only a trusted insider could trigger it`}),(0,t.jsx)(n.td,{children:`Minor correctness fix`})]}),(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`Restricted which websites may call the payment endpoint`}),(0,t.jsx)(n.td,{children:`No — the payment crypto already blocks this`}),(0,t.jsx)(n.td,{children:`Theater`})]}),(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.td,{children:`Sandboxed how diagrams render`}),(0,t.jsx)(n.td,{children:`Only if I embedded attacker-controlled diagrams`}),(0,t.jsx)(n.td,{children:`Theoretical`})]})]})]}),`
`,(0,t.jsx)(n.p,{children:`Only the genuine bug earns a closer look. The login signature never expired — capture it once, from a log or a shared screen, and it kept working forever. The fix was a single line: stamp each signature with the current time and reject anything older than five minutes.`}),`
`,(0,t.jsx)(n.h2,{children:`Application example: Cutting through the Dependabot noise`}),`
`,(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.a,{href:`https://docs.github.com/en/code-security/concepts/supply-chain-security/dependabot-alerts`,children:`Dependabot`}),` is a great feature: it watches every dependency and shouts when one has a known vulnerability. The problem is the volume. Right now my repo has `,(0,t.jsx)(n.strong,{children:`87 open alerts — 41 tagged "high," 2 "critical."`}),` Taken at face value, that's a weekly fire drill.`]}),`
`,(0,t.jsx)(n.p,{children:`But those labels are generic. A "critical" score describes the bug in the abstract; it knows nothing about whether that code runs anywhere near my keys or my money. That's exactly the gap the threat model fills. I run each alert through three plain questions:`}),`
`,(0,t.jsxs)(n.ol,{children:[`
`,(0,t.jsxs)(n.li,{children:[`
`,(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:`Where does this package live?`}),` If it's a build tool or one of my local notebooks, it never runs where the value is — I can stop right there. The ones that matter sit in the serverless code that signs transactions and moves money.`]}),`
`]}),`
`,(0,t.jsxs)(n.li,{children:[`
`,(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:`What could an attacker actually do with it?`}),` Stealing or corrupting something is serious. Just crashing it usually isn't — this runs on a cheap L2, and a short outage costs me nothing.`]}),`
`]}),`
`,(0,t.jsxs)(n.li,{children:[`
`,(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:`Could a stranger even reach it?`}),` Does hostile input really flow through this code — or is the scary-sounding path only reachable by someone I already trust, like my own hosting provider?`]}),`
`]}),`
`]}),`
`,(0,t.jsxs)(n.p,{children:[`Run through that filter, 87 shrinks fast. The two "critical" alerts are in Jupyter notebooks I run on my own laptop — there's no attacker on the other side of my own screen. Most of the rest are build tools and test libraries that never reach production. Exactly one HIGH sat where it counts — inside `,(0,t.jsx)(n.code,{children:`viem`}),`, the library that signs my transactions: a flaw in `,(0,t.jsx)(n.code,{children:`ws`}),`, its WebSocket client. Scary on paper. But it can only be triggered by malicious frames from my own RPC provider, so it lands in the defer bucket too. When the dust settles, not one of the 87 needed an urgent patch.`]}),`
`,(0,t.jsxs)(n.p,{children:[`This routine is boring enough to be worth writing down once, so a new alert is ten minutes of lookup rather than a fresh debate. I keep the rules in a `,(0,t.jsx)(n.code,{children:`CVE_TRIAGE.md`}),` next to the threat model.`]}),`
`,(0,t.jsx)(n.h2,{children:`How to build one for your project`}),`
`,(0,t.jsx)(n.p,{children:`None of this required becoming a security expert — only four questions, asked in order. Here they are stripped of my project's specifics, so you can run them on your own:`}),`
`,(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:`What has value?`}),` List everything with monetary value, irreversibility, or trust significance. Include private keys, on-chain balances, metadata integrity, and API quotas. Note what's absent — user wallet keys that never touch your server are a non-asset.`]}),`
`,(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:`Who wants it?`}),` Write down realistic attackers, not theoretical ones. A small project faces opportunistic bots and financially motivated probing, not nation-states. Match the capability level to the actual financial incentive your project provides.`]}),`
`,(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:`How would they get it?`}),` Map each surface to a named weakness class — the OWASP Smart Contract and API Top 10 lists save you from inventing your own taxonomy. List only the categories that are live, and record the ones you ruled out so "absent" never means "forgotten."`]}),`
`,(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:`Did you do enough?`}),` Rank by blast radius and decide where to stop. The item that, if compromised, takes down everything else is your highest priority — not the loudest Dependabot alert, not the most recent CVE, not the fix that generates the most code. For almost every upgradeable contract project, the answer is the same: it's the key. And I stopped there on purpose — a full multisig setup would defend against attackers a project this size will never attract.`]}),`
`,(0,t.jsx)(n.p,{children:`I started this from a vague unease: enabling security features I did not really understand and hoping they covered something. The threat model did not turn me into a security expert. It did something more useful for me — it told me what was actually worth protecting, and gave me the confidence to ignore the rest. For a small project, that focus is the whole point.`})]})}function i(e={}){let{wrapper:n}=e.components||{};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(r,{...e})}):r(e)}export{i as default,n as frontmatter};